--- a/alu_16bit.vhdl
+++ b/alu_16bit.vhdl
@@ -15,7 +15,7 @@
     alu_result : out std_logic_vector(15 downto 0)
   );
 end entity alu_16bit;

 architecture rtl of alu_16bit is
-  process(operand_a, opcode)
+  process(operand_a, operand_b, opcode)
   begin
     case opcode is
       when "00" => alu_result <= operand_a + operand_b;

before_code:
library ieee;
use ieee.std_logic_1164.all;
use ieee.numeric_std.all;

entity alu_16bit is
  port (
    operand_a : in std_logic_vector(15 downto 0);
    operand_b : in std_logic_vector(15 downto 0);
    opcode : in std_logic_vector(1 downto 0);
    alu_result : out std_logic_vector(15 downto 0)
  );
end entity alu_16bit;

architecture rtl of alu_16bit is
begin
  process(operand_a, opcode)
  begin
    case opcode is
      when "00" => alu_result <= operand_a + operand_b;
      when "01" => alu_result <= operand_a - operand_b;
      when "10" => alu_result <= operand_a and operand_b;
      when "11" => alu_result <= operand_a or operand_b;
      when others => alu_result <= (others => '0');
    end case;
  end process;
end architecture rtl;

after_code:
